export async function seedAuditd() {
    try {
        console.log("Seeding tool Auditd...");
        await Tool.deleteMany({ name: "Auditd" });
        
        const toolDoc = new Tool(toolPayload);
        await toolDoc.save();
        
        console.log("Seeded tool Auditd successfully.");
    } catch (error) {
        console.error("Seeding tool Auditd failed:", error);
        throw error;
    }
}
